    const mergeOptions = (configOptions)=>{
        const merged = {
            ...defaultOptions
        };
        if (configOptions) {
            Object.keys(configOptions).forEach((key)=>{
                const value = configOptions[key];
                if (value !== undefined) {
                    merged[key] = value;
                }
            });
        }
        return merged;
    };
